import{_ as a,o as r,c as t,a2 as i}from"./chunks/framework.BFZItJIV.js";const p=JSON.parse('{"title":"S3 For XunRuiCMS","description":"","frontmatter":{},"headers":[],"relativePath":"zh-Hant/about.md","filePath":"zh-Hant/about.md","lastUpdated":1778063279000}'),l={name:"zh-Hant/about.md"};function n(o,e,h,s,u,c){return r(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="s3-for-xunruicms" tabindex="-1">S3 For XunRuiCMS <a class="header-anchor" href="#s3-for-xunruicms" aria-label="Permalink to &quot;S3 For XunRuiCMS&quot;">​</a></h1><h2 id="項目簡介" tabindex="-1">項目簡介 <a class="header-anchor" href="#項目簡介" aria-label="Permalink to &quot;項目簡介&quot;">​</a></h2><p>S3 For XunRuiCMS 是為迅睿CMS系統提供AWS S3雲存儲支援的插件。</p><h2 id="功能特性" tabindex="-1">功能特性 <a class="header-anchor" href="#功能特性" aria-label="Permalink to &quot;功能特性&quot;">​</a></h2><ul><li>児完整的文檔上 載下管理功能</li><li>支持大文檔分 片上传和断 呈續傳</li><li>与迅睿CMS文檔管理系統无缝集成</li><li>完善的错误处理和 日誌記录</li></ul><h2 id="安裝要求" tabindex="-1">安裝要求 <a class="header-anchor" href="#安裝要求" aria-label="Permalink to &quot;安裝要求&quot;">​</a></h2><ul><li><p>PHP 7.4 或更高版本</p></li><li><p>迦睿CMS v5++</p></li></ul><h2 id="安裝方式" tabindex="-1">安裝方式 <a class="header-anchor" href="#安裝方式" aria-label="Permalink to &quot;安裝方式&quot;">​</a></h2><p>通過迅睿CMS插件市場直接安裝</p><h2 id="使用方法" tabindex="-1">使用方法 <a class="header-anchor" href="#使用方法" aria-label="Permalink to &quot;使用方法&quot;">​</a></h2><ol><li>安裝插件後，在迅睿CMS後台配置 AWS S3 相關信息</li><li>启用插件後，即可在迅睿CMS文件管理中使用 AWS S3 作為存儲</li></ol><h2 id="文檔網站技術架構" tabindex="-1">文檔網站技術架構 <a class="header-anchor" href="#文檔網站技術架構" aria-label="Permalink to &quot;文檔網站技術架構&quot;">​</a></h2><p>本文檔網站基於以下技術構建：</p><p><strong>VitePress</strong> - 靜態網站生成器，版本 ^1.0.0</p><ul><li>官網：<a href="https://vitepress.dev/" target="_blank" rel="noreferrer">https://vitepress.dev/</a></li><li>證書：MIT License</li></ul><p><strong>vitepress-plugin-image-viewer</strong> - 圖片查看器插件，版本 ^1.1.6</p><ul><li>官網：<a href="https://github.com/noonnightrocker/vitepress-plugin-image-viewer" target="_blank" rel="noreferrer">https://github.com/noonnightrocker/vitepress-plugin-image-viewer</a></li><li>證書：MIT License</li></ul><h2 id="致謝" tabindex="-1">致謝 <a class="header-anchor" href="#致謝" aria-label="Permalink to &quot;致謝&quot;">​</a></h2><p>感謝 Vue.js、Vite、VitePress 等开源專案的貢獻者。</p><h2 id="作者資訊" tabindex="-1">作者資訊 <a class="header-anchor" href="#作者資訊" aria-label="Permalink to &quot;作者資訊&quot;">​</a></h2><ul><li>作者：陳延德</li><li>雰箱：<a href="mailto:me@chenyande.com" target="_blank" rel="noreferrer">me@chenyande.com</a></li><li>站點：<a href="https://www.chenyande.com" target="_blank" rel="noreferrer">chenyande.com</a></li></ul><h2 id="�ystenge" tabindex="-1">�ystenge <a class="header-anchor" href="#�ystenge" aria-label="Permalink to &quot;�ystenge&quot;">​</a></h2><p>本專案採用 Apache License 2.2授權</p>',23)])])}const m=a(l,[["render",n]]);export{p as __pageData,m as default};
